exercise.solution_code:
#include <iostream>
#include <string>

int main() {
    int total_sum{0};
    int total_count{0};

    // --- Student 1 ---
    std::string name1{};
    std::cin >> name1;
    {
        int s1{}, s2{};
        std::cin >> s1 >> s2;
        int student_sum{s1 + s2};
        total_sum += student_sum;
        total_count += 2;
        std::cout << name1 << ": " << student_sum / 2 << "\n";
    }

    // --- Student 2 ---
    std::string name2{};
    std::cin >> name2;
    {
        int s1{}, s2{};
        std::cin >> s1 >> s2;
        int student_sum{s1 + s2};
        total_sum += student_sum;
        total_count += 2;
        std::cout << name2 << ": " << student_sum / 2 << "\n";
    }

    std::cout << "Class average: " << total_sum / total_count << "\n";
    return 0;
}
